static void setup_gadgetfs()
{
	if (mkdir("/dev/gadgetfs", 0777)) {
		debug("mkdir(/dev/gadgetfs) failed: %d\n", errno);
	}
	if (mount("gadgetfs", "/dev/gadgetfs", "gadgetfs", 0, NULL)) {
		debug("mount of gadgetfs at /dev/gadgetfs failed: %d\n", errno);
	}
}
